--
-- TOC entry 387 (class 1255 OID 25019)
-- Name: obtener_siguiente_sku(integer); Type: FUNCTION; Schema: public; Owner: ferram
--

CREATE FUNCTION public.obtener_siguiente_sku(p_categoria_id integer) RETURNS character varying
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_prefijo VARCHAR(3);
    v_consecutivo INT;
    v_sku_nuevo VARCHAR;
BEGIN
    -- 1. Obtener las 3 primeras letras de la categoría (Ej: 'Cajas' -> 'CAJ')
    SELECT UPPER(SUBSTRING(nombre, 1, 3)) INTO v_prefijo
    FROM categorias WHERE categoriaid = p_categoria_id;

    -- 2. Buscar el último consecutivo usado para ese prefijo
    -- Extraer solo la parte numérica inmediatamente después del prefijo (antes de cualquier otro guion)
    -- Ejemplo: "CAJ-018-20X20" -> extraer "018" -> convertir a 18
    SELECT COALESCE(
        MAX(
            CAST(
                SUBSTRING(
                    SUBSTRING(sku FROM LENGTH(v_prefijo) + 2),  -- Quitar "CAJ-"
                    '^[0-9]+'  -- Extraer solo dígitos iniciales
                ) 
                AS INT
            )
        ), 
        0
    ) + 1 
    INTO v_consecutivo
    FROM producto_variantes 
    WHERE sku LIKE v_prefijo || '-%'
      AND SUBSTRING(sku FROM LENGTH(v_prefijo) + 2) ~ '^[0-9]+';  -- Solo SKUs que empiecen con números

    -- 3. Formatear (Padding con ceros a la izquierda)
    v_sku_nuevo := v_prefijo || '-' || LPAD(v_consecutivo::TEXT, 3, '0');

    RETURN v_sku_nuevo;
END;
$$;


ALTER FUNCTION public.obtener_siguiente_sku(p_categoria_id integer) OWNER TO ferram;

--
-- TOC entry 395 (class 1255 OID 27621)
-- Name: recalcular_total_pedido(); Type: FUNCTION; Schema: public; Owner: ferram
--

CREATE FUNCTION public.recalcular_total_pedido() RETURNS trigger
    LANGUAGE plpgsql
    AS $_$
DECLARE
    v_pedido_id INTEGER;
    v_subtotal_items NUMERIC(10,2);
    v_monto_descuento NUMERIC(10,2);
    v_total_calculado NUMERIC(10,2);
    v_total_actual NUMERIC(10,2);
    v_diferencia NUMERIC(10,2);
    v_tenant_id INTEGER;
    v_cupon_id INTEGER;
    v_detalles JSONB;
    v_count_items INTEGER;
BEGIN
    -- Determinar el pedido_id según la operación
    IF TG_OP = 'DELETE' THEN
        v_pedido_id := OLD.pedidoid;
    ELSE
        v_pedido_id := NEW.pedidoid;
    END IF;

    -- Obtener información del pedido
    SELECT 
        p.montototal,
        p.monto_descuento,
        p.tenant_id,
        p.cupon_id
    INTO 
        v_total_actual,
        v_monto_descuento,
        v_tenant_id,
        v_cupon_id
    FROM public.pedidos p
    WHERE p.pedidoid = v_pedido_id;

    -- Si el pedido no existe, salir
    IF NOT FOUND THEN
        RETURN COALESCE(NEW, OLD);
    END IF;

    -- CÁLCULO ESTANDARIZADO: Sumar (precioporpaquete * cantidadpaquetes) de todos los items
    -- Fórmula: precioporpaquete = preciounitario * piezas_por_paquete (ya viene calculado)
    -- Subtotal = precioporpaquete * cantidadpaquetes
    SELECT 
        COALESCE(SUM(
            ROUND(d.precioporpaquete * d.cantidadpaquetes, 2)
        ), 0),
        COUNT(*)
    INTO 
        v_subtotal_items,
        v_count_items
    FROM public.detallesdelpedido d
    WHERE d.pedidoid = v_pedido_id;

    -- Aplicar descuento (si existe)
    v_monto_descuento := COALESCE(v_monto_descuento, 0);
    v_total_calculado := ROUND(v_subtotal_items - v_monto_descuento, 2);

    -- Calcular diferencia
    v_diferencia := ABS(v_total_calculado - v_total_actual);

    -- Construir detalles para logging
    v_detalles := jsonb_build_object(
        'subtotal_items', v_subtotal_items,
        'monto_descuento', v_monto_descuento,
        'total_calculado', v_total_calculado,
        'total_actual', v_total_actual,
        'count_items', v_count_items,
        'cupon_id', v_cupon_id,
        'operacion', TG_OP,
        'tabla', TG_TABLE_NAME
    );

    -- VALIDACIÓN: Si hay discrepancia mayor a 1 centavo
    IF v_diferencia > 0.01 THEN
        -- Registrar error en tabla de sincronización
            pedido_id,
            monto_backend,
            monto_calculado,
            diferencia,
            detalles,
            tenant_id
        ) VALUES (
            v_pedido_id,
            v_total_actual,
            v_total_calculado,
            v_diferencia,
            v_detalles,
            v_tenant_id
        );

        -- Emitir NOTICE para logs de Azure
        RAISE NOTICE 'DISCREPANCIA FINANCIERA DETECTADA - Pedido: %, Backend: %, Calculado: %, Diferencia: $%',
            v_pedido_id,
            v_total_actual,
            v_total_calculado,
            v_diferencia;

        -- Emitir WARNING si la diferencia es significativa (>$10)
        IF v_diferencia > 10.00 THEN
            RAISE WARNING 'DISCREPANCIA CRÍTICA - Pedido %: Diferencia de $% excede umbral de seguridad',
                v_pedido_id,
                v_diferencia;
        END IF;
    ELSE
        -- Total correcto - registrar validación exitosa en logs
        RAISE DEBUG 'Validación exitosa - Pedido %: Total correcto ($%)', 
            v_pedido_id, 
            v_total_actual;
    END IF;

    -- IMPORTANTE: NO modificamos el monto en pedidos automáticamente
    -- Solo registramos la discrepancia para revisión manual
    -- Esto evita sobrescribir valores correctos del backend

    RETURN COALESCE(NEW, OLD);
END;
$_$;


ALTER FUNCTION public.recalcular_total_pedido() OWNER TO ferram;

