--
-- TOC entry 396 (class 1255 OID 27625)
-- Name: validar_pedido_manual(integer); Type: FUNCTION; Schema: public; Owner: ferram
--

CREATE FUNCTION public.validar_pedido_manual(p_pedido_id integer) RETURNS TABLE(pedido_id integer, total_actual numeric, total_calculado numeric, diferencia numeric, es_valido boolean, detalles jsonb)
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_subtotal NUMERIC(10,2);
    v_descuento NUMERIC(10,2);
    v_total_actual NUMERIC(10,2);
    v_total_calculado NUMERIC(10,2);
    v_items JSONB;
BEGIN
    -- Obtener total actual y descuento
    SELECT p.montototal, p.monto_descuento
    INTO v_total_actual, v_descuento
    FROM public.pedidos p
    WHERE p.pedidoid = p_pedido_id;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Pedido % no encontrado', p_pedido_id;
    END IF;

    -- Calcular subtotal de items
    SELECT 
        COALESCE(SUM(ROUND(d.precioporpaquete * d.cantidadpaquetes, 2)), 0),
        jsonb_agg(jsonb_build_object(
            'detalle_id', d.detalleid,
            'variante_id', d.varianteid,
            'cantidad', d.cantidadpaquetes,
            'precio_paquete', d.precioporpaquete,
            'precio_unitario', d.preciounitario,
            'subtotal', ROUND(d.precioporpaquete * d.cantidadpaquetes, 2)
        ))
    INTO v_subtotal, v_items
    FROM public.detallesdelpedido d
    WHERE d.pedidoid = p_pedido_id;

    -- Calcular total final
    v_total_calculado := ROUND(v_subtotal - COALESCE(v_descuento, 0), 2);

    -- Retornar resultado
    RETURN QUERY SELECT
        p_pedido_id,
        v_total_actual,
        v_total_calculado,
        ABS(v_total_calculado - v_total_actual),
        ABS(v_total_calculado - v_total_actual) <= 0.01,
        jsonb_build_object(
            'subtotal_items', v_subtotal,
            'monto_descuento', COALESCE(v_descuento, 0),
            'items', v_items
        );
END;
$$;


